/// <summary>
/// Returns a formatted string representation of this data size.
/// </summary>
/// <param name="format">A standard or custom numeric format string.</param>
/// <param name="provider">An object that supplies culture-specific formatting information.</param>
/// <returns>A formatted string representing this data size.</returns>
public string ToString(string? format, IFormatProvider? formatProvider = null)
{
    format ??= "0.## ";
    formatProvider ??= CultureInfo.CurrentCulture;

    if (!format.Contains('#') && !format.Contains('0'))
    {
        format = "0.## " + format;
    }

    var culture = formatProvider as CultureInfo ?? CultureInfo.CurrentCulture;

    // Check for unit symbols and format the corresponding value.
    // Use ordinal comparison for single-char symbols; culture-aware for multi-char.
    if (TryFormatWithUnit(format, culture, formatProvider, TerabyteSymbol, Terabytes, out var result)) return result;
    if (TryFormatWithUnit(format, culture, formatProvider, GigabyteSymbol, Gigabytes, out result)) return result;
    if (TryFormatWithUnit(format, culture, formatProvider, MegabyteSymbol, Megabytes, out result)) return result;
    if (TryFormatWithUnit(format, culture, formatProvider, KilobyteSymbol, Kilobytes, out result)) return result;

    if (format.Contains(ByteSymbol, StringComparison.Ordinal))
        return Bytes.ToString(format, formatProvider);

    if (format.Contains(BitSymbol, StringComparison.Ordinal))
        return ((double)Bits).ToString(format, formatProvider);

    var best = GetLargestWholeNumber();
    return $"{best.Value.ToString(format, formatProvider)} {best.Symbol}";
}

private static bool TryFormatWithUnit(
    string format, CultureInfo culture, IFormatProvider formatProvider,
    string symbol, double value, out string result)
{
    if (culture.CompareInfo.IndexOf(format, symbol, CompareOptions.IgnoreCase) != -1)
    {
        result = value.ToString(format, formatProvider);
        return true;
    }
    result = "";
    return false;
}

