80.     private (double Value, string Symbol) GetLargestWholeNumber()
81.     {
82.         double abs = Math.Abs(Bytes);
83.         if (abs >= BytesInTerabyte) return (Terabytes, TerabyteSymbol);
84.         if (abs >= BytesInGigabyte) return (Gigabytes, GigabyteSymbol);
